module RefModule(clk, rst, en, count);
    input clk;
    input rst;
    input en;
    output reg [7:0] count;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
